//
import { arrayFind, objectValues } from '../utils/zcutils';
import { _modularized } from '../core/zcconf';

function addLegendApi(legends, chartObj) {
    let // Get
        get = id => arrayFind(legends, _ => _.id === id),
        // Behaviour
        behaviour = (id, name, data, ...args) => {
            let legend = legends.get(id);

            if (!legend) {
                return;
            }

            let { view, encode } = legend.meta,
                instanceName = `${fullEncode(encode).toUpperCase()}_${view.toUpperCase()}(${id})`,
                manager = chartObj.legendEvents.eventManager[instanceName],
                bahaviour = getBehaviour(manager, name),
                _data = data.point ? data : { point: data };

            if (!bahaviour) {
                return;
            }

            bahaviour.call(manager, null, _data, ...args);
        };

    // Set
    legends.get = get;
    legends.behaviour = behaviour;
}

function getBehaviour(manager, name) {
    let _behaviours = objectValues(manager.defaultBehaviour),
        found;

    _behaviours.some(b => {
        found = arrayFind(b, _ => smallizeFirstLetter(_.name).replace(/\$(\d+)/, '') === name);
        return found;
    });

    return found;
}

function smallizeFirstLetter(str) {
    return str.charAt(0).toLowerCase() + str.slice(1);
}

function fullEncode(encode) {
    return encode === 'z' ? 'size' : encode === 'clr' ? 'color' : null;
}

export { addLegendApi, fullEncode };
